package com.oyuki.wallet.entity; import com.oyuki.user.entity.User; import com.oyuki.wallet.enums.WithdrawalStatus; import jakarta.persistence.*; import lombok.*; import java.math.BigDecimal; import java.time.LocalDateTime; @Entity @Table(name="withdrawal_requests") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class WithdrawalRequest { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="seller_id") private User seller; @Column(nullable=false,precision=15,scale=2) private BigDecimal amount; @Column(nullable=false,length=120) private String bankName; @Column(nullable=false,length=30) private String accountNumber; @Column(nullable=false,length=150) private String accountName; @Enumerated(EnumType.STRING) @Column(nullable=false,length=30) @Builder.Default private WithdrawalStatus status=WithdrawalStatus.PENDING; @Column(length=1000) private String adminNote; private LocalDateTime createdAt; private LocalDateTime processedAt; @PrePersist void create(){createdAt=LocalDateTime.now();} }